function calculateRisk(inputs) {
  // Input validation and clamping
  const propertyValue = Math.max(0, inputs.propertyValue || 0);
  const historicalSignificance = Math.max(1, Math.min(10, inputs.propertyHistoricalSignificance || 1));
  const previousOwnerControversy = Math.max(1, Math.min(10, inputs.previousOwnerControversyScore || 1));
  const publicProfileVisibility = Math.max(1, Math.min(10, inputs.buyerPublicProfileVisibility || 1));
  const transparencyScore = Math.max(1, Math.min(10, inputs.transactionTransparencyScore || 1));
  const communityImpactSensitivity = Math.max(1, Math.min(10, inputs.localCommunityImpactSensitivity || 1));
  const mediaInterest = Math.max(1, Math.min(10, inputs.mediaInterestPrevalence || 1));
  const socialMediaRisk = Math.max(1, Math.min(10, inputs.socialMediaSentimentRisk || 1));

  // Weighting factors for each input (can be adjusted based on domain expertise)
  const weights = {
    historicalSignificance: 1.5,
    previousOwnerControversy: 2.0,
    publicProfileVisibility: 1.8,
    transactionTransparency: 2.2, // Inverse impact: lower transparency means higher risk
    communityImpact: 1.6,
    mediaInterest: 1.9,
    socialMediaRisk: 1.7
  };

  // Normalize property value to a 1-10 scale for integration
  // Assuming a max 'high-value' property could be $500M for a baseline normalization.
  // This is a rough estimation to give higher value properties more inherent weight.
  const normalizedPropertyValue = Math.min(10, Math.max(1, propertyValue / 5000000)); // $5M for 1, $50M for 10

  // Calculate weighted risk components
  let riskScore = 0;

  // Core property attributes
  riskScore += historicalSignificance * weights.historicalSignificance;
  riskScore += previousOwnerControversy * weights.previousOwnerControversy;
  riskScore += communityImpactSensitivity * weights.communityImpact;

  // Buyer/transaction attributes
  riskScore += publicProfileVisibility * weights.publicProfileVisibility;
  // Transparency reduces risk, so we subtract its normalized value (or add inverse)
  // A score of 10 (very transparent) should reduce risk, so (11 - transparencyScore) converts to a risk increasing factor.
  riskScore += (11 - transparencyScore) * weights.transactionTransparency;

  // External media factors
  riskScore += mediaInterest * weights.mediaInterest;
  riskScore += socialMediaRisk * weights.socialMediaRisk;

  // Add normalized property value as a baseline risk factor (higher value = higher baseline scrutiny)
  riskScore += normalizedPropertyValue * 0.5; // Small constant weight for value itself

  // Max possible raw score (approximate: sum of max weighted inputs)
  // (10*1.5) + (10*2.0) + (10*1.8) + (10*2.2) + (10*1.6) + (10*1.9) + (10*1.7) + (10*0.5) = 15 + 20 + 18 + 22 + 16 + 19 + 17 + 5 = 132
  const maxRawScore = 132; // This might need fine-tuning based on actual max outputs.

  // Normalize to a 0-100 scale
  let overallRiskScore = Math.round((riskScore / maxRawScore) * 100);
  overallRiskScore = Math.max(0, Math.min(100, overallRiskScore)); // Clamp between 0 and 100

  let riskLevel = 'Low';
  if (overallRiskScore >= 75) {
    riskLevel = 'Critical';
  } else if (overallRiskScore >= 50) {
    riskLevel = 'High';
  } else if (overallRiskScore >= 25) {
    riskLevel = 'Moderate';
  }

  return {
    overallRiskScore: overallRiskScore,
    riskLevel: riskLevel
  };
}
